void write_data(char* filename,
		int frameNo,
		int frames_processed,
		int endoPoints,
		int* input_a,
		int* input_b,
		int epiPoints,
		int* input_2a,
		int* input_2b) {

	FILE* fid;
	int i, j;

	fid = fopen(filename, "w+");
	if (fid == NULL) {
		printf("The file was not opened for writing\n");
		return;
	}

	fprintf(fid, "Total AVI Frames: %d\n", frameNo);
	fprintf(fid, "Frames Processed: %d\n", frames_processed);
	fprintf(fid, "endoPoints: %d\n", endoPoints);
	fprintf(fid, "epiPoints: %d", epiPoints);
	for (j = 0; j < frames_processed; j++) {
		fprintf(fid, "\n---Frame %d---", j);
		fprintf(fid, "\n--endo--\n", j);
		for (i = 0; i < endoPoints; i++) {
			fprintf(fid, "%d\t", input_a[j + i * frameNo]);
		}
		fprintf(fid, "\n");
		for (i = 0; i < endoPoints; i++) {
			fprintf(fid, "%d\t", input_b[j + i * frameNo]);
		}
		fprintf(fid, "\n--epi--\n", j);
		for (i = 0; i < epiPoints; i++) {
			fprintf(fid, "%d\t", input_2a[j + i * frameNo]);
		}
		fprintf(fid, "\n");
		for (i = 0; i < epiPoints; i++) {
			fprintf(fid, "%d\t", input_2b[j + i * frameNo]);
		}
	}

	fclose(fid);
}

static void compute_window_sums(const fp *src, params_unique *u, fp *out) {
	int row, col;
	int ori_row, ori_col;
	int position, pos_ori;
	fp sum;

	for (col = 0; col < common.in2_pad_cumv_cols; col++) {
		for (row = 0; row < common.in2_pad_cumv_rows; row++) {
			if (row > (common.in2_pad_add_rows - 1) &&
			    row < (common.in2_pad_add_rows + common.in2_rows) &&
			    col > (common.in2_pad_add_cols - 1) &&
			    col < (common.in2_pad_add_cols + common.in2_cols)) {
				ori_row = row - common.in2_pad_add_rows;
				ori_col = col - common.in2_pad_add_cols;
				u->d_in2_pad_cumv[col * common.in2_pad_cumv_rows + row] =
					src[ori_col * common.in2_rows + ori_row];
			} else {
				u->d_in2_pad_cumv[col * common.in2_pad_cumv_rows + row] = 0;
			}
		}
	}

	for (col = 0; col < common.in2_pad_cumv_cols; col++) {
		pos_ori = col * common.in2_pad_cumv_rows;
		sum = 0;
		for (position = pos_ori; position < pos_ori + common.in2_pad_cumv_rows; position++) {
			u->d_in2_pad_cumv[position] = u->d_in2_pad_cumv[position] + sum;
			sum = u->d_in2_pad_cumv[position];
		}
	}

	for (col = 0; col < common.in2_pad_cumv_sel_cols; col++) {
		for (row = 0; row < common.in2_pad_cumv_sel_rows; row++) {
			ori_row = row + common.in2_pad_cumv_sel_rowlow - 1;
			ori_col = col + common.in2_pad_cumv_sel_collow - 1;
			u->d_in2_pad_cumv_sel[col * common.in2_pad_cumv_sel_rows + row] =
				u->d_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];
		}
	}

	for (col = 0; col < common.in2_sub_cumh_cols; col++) {
		for (row = 0; row < common.in2_sub_cumh_rows; row++) {
			ori_row = row + common.in2_pad_cumv_sel2_rowlow - 1;
			ori_col = col + common.in2_pad_cumv_sel2_collow - 1;
			u->d_in2_sub_cumh[col * common.in2_sub_cumh_rows + row] =
				u->d_in2_pad_cumv[ori_col * common.in2_pad_cumv_rows + ori_row];
		}
	}

	for (position = 0; position < common.in2_sub_cumh_elem; position++) {
		u->d_in2_sub_cumh[position] =
			u->d_in2_pad_cumv_sel[position] - u->d_in2_sub_cumh[position];
	}

	for (row = 0; row < common.in2_sub_cumh_rows; row++) {
		pos_ori = row;
		sum = 0;
		for (position = pos_ori; position < pos_ori + common.in2_sub_cumh_elem; position += common.in2_sub_cumh_rows) {
			u->d_in2_sub_cumh[position] = u->d_in2_sub_cumh[position] + sum;
			sum = u->d_in2_sub_cumh[position];
		}
	}

	for (col = 0; col < common.in2_sub_cumh_sel_cols; col++) {
		for (row = 0; row < common.in2_sub_cumh_sel_rows; row++) {
			ori_row = row + common.in2_sub_cumh_sel_rowlow - 1;
			ori_col = col + common.in2_sub_cumh_sel_collow - 1;
			u->d_in2_sub_cumh_sel[col * common.in2_sub_cumh_sel_rows + row] =
				u->d_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];
		}
	}

	for (col = 0; col < common.in2_sub2_cols; col++) {
		for (row = 0; row < common.in2_sub2_rows; row++) {
			ori_row = row + common.in2_sub_cumh_sel2_rowlow - 1;
			ori_col = col + common.in2_sub_cumh_sel2_collow - 1;
			out[col * common.in2_sub2_rows + row] =
				u->d_in2_sub_cumh_sel[col * common.in2_sub_cumh_sel_rows + row] -
				u->d_in2_sub_cumh[ori_col * common.in2_sub_cumh_rows + ori_row];
		}
	}
}

static void process_point(int bx) {
	params_unique *u = &unique[bx];
	fp *d_in = NULL;
	int rot_row;
	int rot_col;
	int in2_rowlow;
	int in2_collow;
	int ic;
	int jc;
	int jp1;
	int ja1, ja2;
	int ip1;
	int ia1, ia2;
	int ja, jb;
	int ia, ib;
	fp s;
	int i;
	int row;
	int col;
	int ori_row;
	int ori_col;
	int position;
	fp sum;
	int pos_ori;
	fp temp;
	fp temp2;
	int location;
	int cent;
	int tMask_row;
	int tMask_col;
	fp largest_value_current;
	fp fin_max_val;
	int fin_max_coo;
	int largest_row;
	int largest_col;
	int offset_row;
	int offset_col;
	fp in_final_sum;
	fp in_sqr_final_sum;
	fp mean;
	fp mean_sqr;
	fp variance;
	fp deviation;
	fp denomT;
	int pointer;
	int ori_pointer;
	int loc_pointer;
	fp d_in_mod_temp[2601];
	fp in_partial_sum[51];
	fp in_sqr_partial_sum[51];

	if (common_change.frame_no == 0) {
		d_in = &u->d_T[u->in_pointer];

		pointer = u->point_no * common.no_frames + common_change.frame_no;
		u->d_tRowLoc[pointer] = u->d_Row[u->point_no];
		u->d_tColLoc[pointer] = u->d_Col[u->point_no];

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				ori_row = u->d_Row[u->point_no] - common.tSize + row - 1;
				ori_col = u->d_Col[u->point_no] - common.tSize + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;
				d_in[col * common.in_rows + row] = common_change.d_frame[ori_pointer];
			}
		}
	}

	if (common_change.frame_no != 0) {
		in2_rowlow = u->d_Row[u->point_no] - common.sSize;
		in2_collow = u->d_Col[u->point_no] - common.sSize;

		for (col = 0; col < common.in2_cols; col++) {
			for (row = 0; row < common.in2_rows; row++) {
				ori_row = row + in2_rowlow - 1;
				ori_col = col + in2_collow - 1;
				u->d_in2[col * common.in2_rows + row] =
					common_change.d_frame[ori_col * common.frame_rows + ori_row];
			}
		}

		d_in = &u->d_T[u->in_pointer];

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				rot_row = (common.in_rows - 1) - row;
				rot_col = (common.in_rows - 1) - col;
				d_in_mod_temp[col * common.in_rows + row] =
					d_in[rot_col * common.in_rows + rot_row];
			}
		}

		for (jc = 1; jc <= common.conv_cols; jc++) {
			int j = jc + common.joffset;
			jp1 = j + 1;
			if (common.in2_cols < jp1) {
				ja1 = jp1 - common.in2_cols;
			} else {
				ja1 = 1;
			}
			if (common.in_cols < j) {
				ja2 = common.in_cols;
			} else {
				ja2 = j;
			}

			for (ic = 1; ic <= common.conv_rows; ic++) {
				int jdummy = 0;
				(void)jdummy;
				int ii = ic + common.ioffset;
				ip1 = ii + 1;

				if (common.in2_rows < ip1) {
					ia1 = ip1 - common.in2_rows;
				} else {
					ia1 = 1;
				}
				if (common.in_rows < ii) {
					ia2 = common.in_rows;
				} else {
					ia2 = ii;
				}

				s = 0;
				for (ja = ja1; ja <= ja2; ja++) {
					jb = jp1 - ja;
					for (ia = ia1; ia <= ia2; ia++) {
						ib = ip1 - ia;
						s = s + d_in_mod_temp[common.in_rows * (ja - 1) + ia - 1] *
							u->d_in2[common.in2_rows * (jb - 1) + ib - 1];
					}
				}

				u->d_conv[(jc - 1) * common.conv_rows + (ic - 1)] = s;
			}
		}

		compute_window_sums(u->d_in2, u, u->d_in2_sub2);

		for (i = 0; i < common.in2_sqr_elem; i++) {
			temp = u->d_in2[i];
			u->d_in2_sqr[i] = temp * temp;
		}

		compute_window_sums(u->d_in2_sqr, u, u->d_in2_sqr_sub2);

		for (i = 0; i < common.in2_sub2_elem; i++) {
			temp = u->d_in2_sub2[i];
			temp2 = u->d_in2_sqr_sub2[i] - (temp * temp / common.in_elem);
			if (temp2 < 0) {
				temp2 = 0;
			}
			u->d_in2_sqr_sub2[i] = sqrtf(temp2);
		}

		for (i = 0; i < common.in_sqr_elem; i++) {
			temp = d_in[i];
			u->d_in_sqr[i] = temp * temp;
		}

		for (col = 0; col < common.in_cols; col++) {
			sum = 0;
			for (i = 0; i < common.in_rows; i++) {
				sum = sum + d_in[col * common.in_rows + i];
			}
			in_partial_sum[col] = sum;
		}

		for (row = 0; row < common.in_sqr_rows; row++) {
			sum = 0;
			for (i = 0; i < common.in_sqr_cols; i++) {
				sum = sum + u->d_in_sqr[row + common.in_sqr_rows * i];
			}
			in_sqr_partial_sum[row] = sum;
		}

		in_final_sum = 0;
		for (i = 0; i < common.in_cols; i++) {
			in_final_sum = in_final_sum + in_partial_sum[i];
		}

		in_sqr_final_sum = 0;
		for (i = 0; i < common.in_sqr_cols; i++) {
			in_sqr_final_sum = in_sqr_final_sum + in_sqr_partial_sum[i];
		}

		mean = in_final_sum / common.in_elem;
		mean_sqr = mean * mean;
		variance = (in_sqr_final_sum / common.in_elem) - mean_sqr;
		deviation = sqrtf(variance);
		denomT = sqrtf((fp)(common.in_elem - 1)) * deviation;

		for (i = 0; i < common.in2_sub2_elem; i++) {
			u->d_in2_sqr_sub2[i] = u->d_in2_sqr_sub2[i] * denomT;
		}

		for (i = 0; i < common.conv_elem; i++) {
			u->d_conv[i] = u->d_conv[i] - u->d_in2_sub2[i] * in_final_sum / common.in_elem;
		}

		for (i = 0; i < common.in2_sub2_elem; i++) {
			u->d_in2_sqr_sub2[i] = u->d_conv[i] / u->d_in2_sqr_sub2[i];
		}

		cent = common.sSize + common.tSize + 1;
		if (common_change.frame_no == 0) {
			tMask_row = cent + u->d_Row[u->point_no] - u->d_Row[u->point_no] - 1;
			tMask_col = cent + u->d_Col[u->point_no] - u->d_Col[u->point_no] - 1;
		} else {
			pointer = common_change.frame_no - 1 + u->point_no * common.no_frames;
			tMask_row = cent + u->d_tRowLoc[pointer] - u->d_Row[u->point_no] - 1;
			tMask_col = cent + u->d_tColLoc[pointer] - u->d_Col[u->point_no] - 1;
		}

		location = tMask_col * common.tMask_rows + tMask_row;
		for (i = 0; i < common.tMask_elem; i++) {
			if (i == location) {
				u->d_tMask[i] = 1;
			} else {
				u->d_tMask[i] = 0;
			}
		}

		for (jc = 1; jc <= common.mask_conv_cols; jc++) {
			int j = jc + common.mask_conv_joffset;
			jp1 = j + 1;
			if (common.mask_cols < jp1) {
				ja1 = jp1 - common.mask_cols;
			} else {
				ja1 = 1;
			}
			if (common.tMask_cols < j) {
				ja2 = common.tMask_cols;
			} else {
				ja2 = j;
			}

			for (ic = 1; ic <= common.mask_conv_rows; ic++) {
				int ii = ic + common.mask_conv_ioffset;
				ip1 = ii + 1;

				if (common.mask_rows < ip1) {
					ia1 = ip1 - common.mask_rows;
				} else {
					ia1 = 1;
				}
				if (common.tMask_rows < ii) {
					ia2 = common.tMask_rows;
				} else {
					ia2 = ii;
				}

				s = 0;
				for (ja = ja1; ja <= ja2; ja++) {
					jb = jp1 - ja;
					for (ia = ia1; ia <= ia2; ia++) {
						ib = ip1 - ia;
						(void)jb;
						(void)ib;
						s = s + u->d_tMask[common.tMask_rows * (ja - 1) + ia - 1] * 1;
					}
				}

				u->d_mask_conv[(jc - 1) * common.mask_conv_rows + (ic - 1)] =
					u->d_in2_sqr_sub2[(jc - 1) * common.mask_conv_rows + (ic - 1)] * s;
			}
		}

		fin_max_val = 0;
		fin_max_coo = 0;
		for (i = 0; i < common.mask_conv_elem; i++) {
			largest_value_current = fabsf(u->d_mask_conv[i]);
			if (largest_value_current > fin_max_val) {
				fin_max_val = largest_value_current;
				fin_max_coo = i;
			}
		}

		largest_row = (fin_max_coo + 1) % common.mask_conv_rows - 1;
		largest_col = (fin_max_coo + 1) / common.mask_conv_rows;
		if ((fin_max_coo + 1) % common.mask_conv_rows == 0) {
			largest_row = common.mask_conv_rows - 1;
			largest_col = largest_col - 1;
		}

		largest_row = largest_row + 1;
		largest_col = largest_col + 1;
		offset_row = largest_row - common.in_rows - (common.sSize - common.tSize);
		offset_col = largest_col - common.in_cols - (common.sSize - common.tSize);
		pointer = common_change.frame_no + u->point_no * common.no_frames;
		u->d_tRowLoc[pointer] = u->d_Row[u->point_no] + offset_row;
		u->d_tColLoc[pointer] = u->d_Col[u->point_no] + offset_col;
	}

	if (common_change.frame_no != 0 && (common_change.frame_no) % 10 == 0) {
		d_in = &u->d_T[u->in_pointer];

		loc_pointer = u->point_no * common.no_frames + common_change.frame_no;
		u->d_Row[u->point_no] = u->d_tRowLoc[loc_pointer];
		u->d_Col[u->point_no] = u->d_tColLoc[loc_pointer];

		for (col = 0; col < common.in_cols; col++) {
			for (row = 0; row < common.in_rows; row++) {
				ori_row = u->d_Row[u->point_no] - common.tSize + row - 1;
				ori_col = u->d_Col[u->point_no] - common.tSize + col - 1;
				ori_pointer = ori_col * common.frame_rows + ori_row;
				d_in[col * common.in_rows + row] =
					common.alpha * d_in[col * common.in_rows + row] +
